library(inline)
library(Rcpp)

fx <- cxxfunction(signature(),
                  includes = paste(readLines("PnL module.cpp"),
                    collapse =  "\n"),
                  plugin = "Rcpp")

port <- Module("PortPL_module", getDynLib(fx))
PortPL <- port$PortPL

datel <- as.POSIXct(Sys.Date()+1:10)
